1	`timescale 1ns / 1ps
2	
3	/**
4	 * usb_data_interface_ft2232h.v
5	 *
6	 * FT2232H USB 2.0 Hi-Speed FIFO Interface (245 Synchronous FIFO Mode)
7	 * Channel A only — 8-bit data bus, 60 MHz CLKOUT from FT2232H.
8	 *
9	 * This module is the 50T production board equivalent of usb_data_interface.v
10	 * (FT601, 32-bit, USB 3.0). Both share the same internal interface signals
11	 * so they can be swapped via a generate block in radar_system_top.v.
12	 *
13	 * Data packet (FPGA→Host): 11 bytes
14	 *   Byte 0:    0xAA (header)
15	 *   Bytes 1-4: range_profile[31:0] = {range_q[15:0], range_i[15:0]} MSB first
16	 *   Bytes 5-6: doppler_real[15:0] MSB first
17	 *   Bytes 7-8: doppler_imag[15:0] MSB first
18	 *   Byte 9:    {7'b0, cfar_detection}
19	 *   Byte 10:   0x55 (footer)
20	 *
21	 * Status packet (FPGA→Host): 26 bytes
22	 *   Byte 0:     0xBB (status header)
23	 *   Bytes 1-24: 6 × 32-bit status words, MSB first
24	 *   Byte 25:    0x55 (footer)
25	 *
26	 * Command (Host→FPGA): 4 bytes received sequentially
27	 *   Byte 0: opcode[7:0]
28	 *   Byte 1: addr[7:0]
29	 *   Byte 2: value[15:8]
30	 *   Byte 3: value[7:0]
31	 *
32	 * CDC: Toggle CDC (not level sync) for all valid pulse crossings from
33	 * 100 MHz → 60 MHz. Toggle CDC is guaranteed to work regardless of
34	 * clock frequency ratio.
35	 *
36	 * Clock domains:
37	 *   clk       = 100 MHz system clock (radar data domain)
38	 *   ft_clk    = 60 MHz from FT2232H CLKOUT (USB FIFO domain)
39	 *
40	 * USB disconnect recovery:
41	 *   A clock-activity watchdog in the clk domain detects when ft_clk stops
42	 *   (USB cable unplugged). After ~0.65 ms of silence (65536 system clocks)
43	 *   it asserts ft_clk_lost, which is OR'd into the FT-domain reset so
44	 *   FSMs and FIFOs return to a clean state. When ft_clk resumes, a 2-stage
45	 *   reset synchronizer deasserts the reset cleanly in the ft_clk domain.
46	 */
47	
48	module usb_data_interface_ft2232h (
49	    input wire clk,              // Main clock (100 MHz)
50	    input wire reset_n,          // System reset (clk domain)
51	    input wire ft_reset_n,       // FT2232H-domain synchronized reset
52	
53	    // Radar data inputs (clk domain)
54	    input wire [31:0] range_profile,
55	    input wire range_valid,
56	    input wire [15:0] doppler_real,
57	    input wire [15:0] doppler_imag,
58	    input wire doppler_valid,
59	    input wire cfar_detection,
60	    input wire cfar_valid,
61	
62	    // FT2232H Physical Interface (245 Synchronous FIFO mode)
63	    inout wire [7:0] ft_data,       // 8-bit bidirectional data bus
64	    input wire ft_rxf_n,            // Receive FIFO not empty (active low)
65	    input wire ft_txe_n,            // Transmit FIFO not full (active low)
66	    output reg ft_rd_n,             // Read strobe (active low)
67	    output reg ft_wr_n,             // Write strobe (active low)
68	    output reg ft_oe_n,             // Output enable (active low) — bus direction
69	    output reg ft_siwu,             // Send Immediate / WakeUp — UNUSED: held low.
70	                                    // SIWU could flush the TX FIFO for lower latency
71	                                    // but is not needed at current data rates. Deferred.
72	
73	    // Clock from FT2232H (directly used — no ODDR forwarding needed)
74	    input wire ft_clk,              // 60 MHz from FT2232H CLKOUT
75	
76	    // Host command outputs (ft_clk domain — CDC'd by consumer)
77	    output reg [31:0] cmd_data,
78	    output reg cmd_valid,
79	    output reg [7:0] cmd_opcode,
80	    output reg [7:0] cmd_addr,
81	    output reg [15:0] cmd_value,
82	
83	    // Stream control input (clk domain, CDC'd internally)
84	    input wire [2:0] stream_control,
85	
86	    // Status readback inputs (clk domain, CDC'd internally)
87	    input wire status_request,
88	    input wire [15:0] status_cfar_threshold,
89	    input wire [2:0]  status_stream_ctrl,
90	    input wire [1:0]  status_radar_mode,
91	    input wire [15:0] status_long_chirp,
92	    input wire [15:0] status_long_listen,
93	    input wire [15:0] status_guard,
94	    input wire [15:0] status_short_chirp,
95	    input wire [15:0] status_short_listen,
96	    input wire [5:0]  status_chirps_per_elev,
97	    input wire [1:0]  status_range_mode,
98	
99	    // Self-test status readback
100	    input wire [4:0]  status_self_test_flags,
101	    input wire [7:0]  status_self_test_detail,
102	    input wire        status_self_test_busy,
103	
104	    // AGC status readback
105	    input wire [3:0]  status_agc_current_gain,
106	    input wire [7:0]  status_agc_peak_magnitude,
107	    input wire [7:0]  status_agc_saturation_count,
108	    input wire        status_agc_enable
109	);
110	
111	// ============================================================================
112	// PACKET FORMAT CONSTANTS
113	// ============================================================================
114	localparam HEADER        = 8'hAA;
115	localparam FOOTER        = 8'h55;
116	localparam STATUS_HEADER = 8'hBB;
117	
118	// Data packet: 11 bytes total
119	localparam DATA_PKT_LEN    = 5'd11;
120	// Status packet: 26 bytes total (1 header + 24 data + 1 footer)
121	localparam STATUS_PKT_LEN  = 5'd26;
122	
123	// ============================================================================
124	// WRITE FSM STATES (FPGA → Host)
125	// ============================================================================
126	localparam [2:0] WR_IDLE          = 3'd0,
127	                 WR_DATA_SEND     = 3'd1,
128	                 WR_STATUS_SEND   = 3'd2,
129	                 WR_DONE          = 3'd3;
130	
131	reg [2:0] wr_state;
132	reg [4:0] wr_byte_idx;   // Byte counter within packet (0..10 data, 0..25 status)
133	
134	// ============================================================================
135	// READ FSM STATES (Host → FPGA)
136	// ============================================================================
137	localparam [2:0] RD_IDLE       = 3'd0,
138	                 RD_OE_ASSERT  = 3'd1,
139	                 RD_READING    = 3'd2,
140	                 RD_DEASSERT   = 3'd3,
141	                 RD_PROCESS    = 3'd4;
142	
143	reg [2:0] rd_state;
144	reg [1:0] rd_byte_cnt;   // 0..3 for 4-byte command word
145	reg [31:0] rd_shift_reg;  // Shift register to assemble 4-byte command
146	reg rd_cmd_complete;      // Set when all 4 bytes received (distinguishes from abort)
147	
148	// ============================================================================
149	// DATA BUS DIRECTION CONTROL
150	// ============================================================================
151	reg [7:0] ft_data_out;
152	reg ft_data_oe;  // 1 = FPGA drives bus, 0 = FT2232H drives bus
153	
154	assign ft_data = ft_data_oe ? ft_data_out : 8'hZZ;
155	
156	// ============================================================================
157	// TOGGLE CDC: clk (100 MHz) → ft_clk (60 MHz)
158	// ============================================================================
159	// Toggle CDC is used instead of level synchronizers because a 10 ns pulse
160	// on clk_100m could be missed by the 16.67 ns ft_clk period. Toggle CDC
161	// converts pulses to level transitions, which are always captured.
162	
163	// --- Toggle registers (clk domain) ---
164	reg range_valid_toggle;
165	reg doppler_valid_toggle;
166	reg cfar_valid_toggle;
167	reg status_req_toggle;
168	
169	// --- Holding registers (clk domain) ---
170	// Data captured on valid pulse, held stable for ft_clk domain to read
171	reg [31:0] range_profile_hold;
172	reg [15:0] doppler_real_hold;
173	reg [15:0] doppler_imag_hold;
174	reg cfar_detection_hold;
175	
176	always @(posedge clk or negedge reset_n) begin
177	    if (!reset_n) begin
178	        range_valid_toggle   <= 1'b0;
179	        doppler_valid_toggle <= 1'b0;
180	        cfar_valid_toggle    <= 1'b0;
181	        status_req_toggle    <= 1'b0;
182	        range_profile_hold   <= 32'd0;
183	        doppler_real_hold    <= 16'd0;
184	        doppler_imag_hold    <= 16'd0;
185	        cfar_detection_hold  <= 1'b0;
186	    end else begin
187	        if (range_valid) begin
188	            range_valid_toggle  <= ~range_valid_toggle;
189	            range_profile_hold  <= range_profile;
190	        end
191	        if (doppler_valid) begin
192	            doppler_valid_toggle <= ~doppler_valid_toggle;
193	            doppler_real_hold    <= doppler_real;
194	            doppler_imag_hold    <= doppler_imag;
195	        end
196	        if (cfar_valid) begin
197	            cfar_valid_toggle   <= ~cfar_valid_toggle;
198	            cfar_detection_hold <= cfar_detection;
199	        end
200	        if (status_request)
201	            status_req_toggle <= ~status_req_toggle;
202	    end
203	end
204	
205	// ============================================================================
206	// CLOCK-ACTIVITY WATCHDOG (clk domain)
207	// ============================================================================
208	// Detects when ft_clk stops (USB cable unplugged). A toggle register in the
209	// ft_clk domain flips every ft_clk edge. The clk domain synchronizes it and
210	// checks for transitions. If no transition is seen for 2^16 = 65536 clk
211	// cycles (~0.65 ms at 100 MHz), ft_clk_lost asserts.
212	//
213	// ft_clk_lost feeds into the effective reset for the ft_clk domain so that
214	// FSMs and capture registers return to a clean state automatically.
215	
216	// Toggle register: flips every ft_clk edge (ft_clk domain)
217	reg ft_heartbeat;
218	always @(posedge ft_clk or negedge ft_reset_n) begin
219	    if (!ft_reset_n)
220	        ft_heartbeat <= 1'b0;
221	    else
222	        ft_heartbeat <= ~ft_heartbeat;
223	end
224	
225	// Synchronize heartbeat into clk domain (2-stage)
226	(* ASYNC_REG = "TRUE" *) reg [1:0] ft_hb_sync;
227	reg ft_hb_prev;
228	reg [15:0] ft_clk_timeout;
229	reg ft_clk_lost;
230	
231	always @(posedge clk or negedge reset_n) begin
232	    if (!reset_n) begin
233	        ft_hb_sync    <= 2'b00;
234	        ft_hb_prev    <= 1'b0;
235	        ft_clk_timeout <= 16'd0;
236	        ft_clk_lost   <= 1'b0;
237	    end else begin
238	        ft_hb_sync <= {ft_hb_sync[0], ft_heartbeat};
239	        ft_hb_prev <= ft_hb_sync[1];
240	
241	        if (ft_hb_sync[1] != ft_hb_prev) begin
242	            // ft_clk is alive — reset counter, clear lost flag
243	            ft_clk_timeout <= 16'd0;
244	            ft_clk_lost    <= 1'b0;
245	        end else if (!ft_clk_lost) begin
246	            if (ft_clk_timeout == 16'hFFFF)
247	                ft_clk_lost <= 1'b1;
248	            else
249	                ft_clk_timeout <= ft_clk_timeout + 16'd1;
250	        end
251	    end
252	end
253	
254	// Effective FT-domain reset: asserted by global reset OR clock loss.
255	// Deassertion synchronized to ft_clk via 2-stage sync to avoid
256	// metastability on the recovery edge.
257	(* ASYNC_REG = "TRUE" *) reg [1:0] ft_reset_sync;
258	wire ft_reset_raw_n = ft_reset_n & ~ft_clk_lost;
259	
260	always @(posedge ft_clk or negedge ft_reset_raw_n) begin
261	    if (!ft_reset_raw_n)
262	        ft_reset_sync <= 2'b00;
263	    else
264	        ft_reset_sync <= {ft_reset_sync[0], 1'b1};
265	end
266	
267	wire ft_effective_reset_n = ft_reset_sync[1];
268	
269	// --- 3-stage synchronizers (ft_clk domain) ---
270	// 3 stages for better MTBF at 60 MHz
271	
272	(* ASYNC_REG = "TRUE" *) reg [2:0] range_toggle_sync;
273	(* ASYNC_REG = "TRUE" *) reg [2:0] doppler_toggle_sync;
274	(* ASYNC_REG = "TRUE" *) reg [2:0] cfar_toggle_sync;
275	(* ASYNC_REG = "TRUE" *) reg [2:0] status_toggle_sync;
276	
277	reg range_toggle_prev;
278	reg doppler_toggle_prev;
279	reg cfar_toggle_prev;
280	reg status_toggle_prev;
281	
282	// Edge-detected pulses in ft_clk domain
283	wire range_valid_ft   = range_toggle_sync[2]   ^ range_toggle_prev;
284	wire doppler_valid_ft = doppler_toggle_sync[2]  ^ doppler_toggle_prev;
285	wire cfar_valid_ft    = cfar_toggle_sync[2]     ^ cfar_toggle_prev;
286	wire status_req_ft    = status_toggle_sync[2]   ^ status_toggle_prev;
287	
288	// --- Stream control CDC (per-bit 2-stage, changes infrequently) ---
289	(* ASYNC_REG = "TRUE" *) reg [2:0] stream_ctrl_sync_0;
290	(* ASYNC_REG = "TRUE" *) reg [2:0] stream_ctrl_sync_1;
291	wire stream_range_en   = stream_ctrl_sync_1[0];
292	wire stream_doppler_en = stream_ctrl_sync_1[1];
293	wire stream_cfar_en    = stream_ctrl_sync_1[2];
294	
295	// --- Captured data in ft_clk domain ---
296	reg [31:0] range_profile_cap;
297	reg [15:0] doppler_real_cap;
298	reg [15:0] doppler_imag_cap;
299	reg cfar_detection_cap;
300	
301	// Data-pending flags (ft_clk domain)
302	reg doppler_data_pending;
303	reg cfar_data_pending;
304	
305	// 1-cycle delayed range trigger.  range_valid_ft fires on the same clock
306	// edge that range_profile_cap is captured (non-blocking).  If the FSM
307	// reads range_profile_cap on that same edge it sees the STALE value.
308	// Delaying the trigger by one cycle guarantees the capture register has
309	// settled before the byte mux reads it.
310	reg range_data_ready;
311	
312	// Frame sync: sample counter (ft_clk domain, wraps at NUM_CELLS)
313	// Bit 7 of detection byte is set when sample_counter == 0 (frame start).
314	// This allows the Python host to resynchronize without a protocol change.
315	localparam [11:0] NUM_CELLS = 12'd2048;  // 64 range x 32 doppler
316	reg [11:0] sample_counter;
317	
318	// Status snapshot (ft_clk domain)
319	reg [31:0] status_words [0:5];
320	
321	integer si;  // status_words loop index
322	always @(posedge ft_clk or negedge ft_effective_reset_n) begin
323	    if (!ft_effective_reset_n) begin
324	        range_toggle_sync   <= 3'b000;
325	        doppler_toggle_sync <= 3'b000;
326	        cfar_toggle_sync    <= 3'b000;
327	        status_toggle_sync  <= 3'b000;
328	        range_toggle_prev   <= 1'b0;
329	        doppler_toggle_prev <= 1'b0;
330	        cfar_toggle_prev    <= 1'b0;
331	        status_toggle_prev  <= 1'b0;
332	        range_profile_cap   <= 32'd0;
333	        doppler_real_cap    <= 16'd0;
334	        doppler_imag_cap    <= 16'd0;
335	        cfar_detection_cap  <= 1'b0;
336	        range_data_ready    <= 1'b0;
337	        // Default to range-only on reset (prevents write FSM deadlock)
338	        stream_ctrl_sync_0  <= 3'b001;
339	        stream_ctrl_sync_1  <= 3'b001;
340	        // Explicit reset for status_words to avoid Synth 8-7137
341	        for (si = 0; si < 6; si = si + 1)
342	            status_words[si] <= 32'd0;
343	    end else begin
344	        // 3-stage toggle synchronizers
345	        range_toggle_sync   <= {range_toggle_sync[1:0],   range_valid_toggle};
346	        doppler_toggle_sync <= {doppler_toggle_sync[1:0], doppler_valid_toggle};
347	        cfar_toggle_sync    <= {cfar_toggle_sync[1:0],    cfar_valid_toggle};
348	        status_toggle_sync  <= {status_toggle_sync[1:0],  status_req_toggle};
349	
350	        // Previous toggle value for edge detection
351	        range_toggle_prev   <= range_toggle_sync[2];
352	        doppler_toggle_prev <= doppler_toggle_sync[2];
353	        cfar_toggle_prev    <= cfar_toggle_sync[2];
354	        status_toggle_prev  <= status_toggle_sync[2];
355	
356	        // Stream control CDC (2-stage)
357	        stream_ctrl_sync_0 <= stream_control;
358	        stream_ctrl_sync_1 <= stream_ctrl_sync_0;
359	
360	        // Capture data on toggle edge
361	        if (range_valid_ft)
362	            range_profile_cap <= range_profile_hold;
363	        if (doppler_valid_ft) begin
364	            doppler_real_cap <= doppler_real_hold;
365	            doppler_imag_cap <= doppler_imag_hold;
366	        end
367	        if (cfar_valid_ft)
368	            cfar_detection_cap <= cfar_detection_hold;
369	
370	        // 1-cycle delayed trigger: ensures range_profile_cap has settled
371	        // before the FSM reads it via the byte mux.
372	        range_data_ready <= range_valid_ft;
373	
374	        // Status snapshot on request
375	        if (status_req_ft) begin
376	            // Word 0: {0xFF[31:24], mode[23:22], stream[21:19], 3'b000[18:16], threshold[15:0]}
377	            status_words[0] <= {8'hFF, status_radar_mode, status_stream_ctrl,
378	                                3'b000, status_cfar_threshold};
379	            status_words[1] <= {status_long_chirp, status_long_listen};
380	            status_words[2] <= {status_guard, status_short_chirp};
381	            status_words[3] <= {status_short_listen, 10'd0, status_chirps_per_elev};
382	            status_words[4] <= {status_agc_current_gain,        // [31:28]
383	                                status_agc_peak_magnitude,      // [27:20]
384	                                status_agc_saturation_count,    // [19:12]
385	                                status_agc_enable,              // [11]
386	                                9'd0,                           // [10:2] reserved
387	                                status_range_mode};             // [1:0]
388	            status_words[5] <= {7'd0, status_self_test_busy,
389	                                8'd0, status_self_test_detail,
390	                                3'd0, status_self_test_flags};
391	        end
392	    end
393	end
394	
395	// ============================================================================
396	// WRITE DATA MUX — byte selection for data packet (11 bytes)
397	// ============================================================================
398	// Mux-based byte selection is simpler than a shift register and gives
399	// explicit byte ordering for synthesis.
400	
401	reg [7:0] data_pkt_byte;
402	
403	always @(*) begin
404	    case (wr_byte_idx)
405	        5'd0:  data_pkt_byte = HEADER;
406	        5'd1:  data_pkt_byte = range_profile_cap[31:24];   // range MSB
407	        5'd2:  data_pkt_byte = range_profile_cap[23:16];
408	        5'd3:  data_pkt_byte = range_profile_cap[15:8];
409	        5'd4:  data_pkt_byte = range_profile_cap[7:0];     // range LSB
410	        // Doppler fields: zero when stream_doppler_en is off
411	        5'd5:  data_pkt_byte = stream_doppler_en ? doppler_real_cap[15:8]  : 8'd0;
412	        5'd6:  data_pkt_byte = stream_doppler_en ? doppler_real_cap[7:0]   : 8'd0;
413	        5'd7:  data_pkt_byte = stream_doppler_en ? doppler_imag_cap[15:8]  : 8'd0;
414	        5'd8:  data_pkt_byte = stream_doppler_en ? doppler_imag_cap[7:0]   : 8'd0;
415	        // Detection field: zero when stream_cfar_en is off
416	        // Bit 7 = frame_start flag (sample_counter == 0), bit 0 = cfar_detection
417	        5'd9:  data_pkt_byte = stream_cfar_en
418	                   ? {(sample_counter == 12'd0), 6'b0, cfar_detection_cap}
419	                   : {(sample_counter == 12'd0), 7'd0};
420	        5'd10: data_pkt_byte = FOOTER;
421	        default: data_pkt_byte = 8'h00;
422	    endcase
423	end
424	
425	// ============================================================================
426	// WRITE DATA MUX — byte selection for status packet (26 bytes)
427	// ============================================================================
428	
429	reg [7:0] status_pkt_byte;
430	
431	always @(*) begin
432	    case (wr_byte_idx)
433	        5'd0:  status_pkt_byte = STATUS_HEADER;
434	        // Word 0 (bytes 1-4)
435	        5'd1:  status_pkt_byte = status_words[0][31:24];
436	        5'd2:  status_pkt_byte = status_words[0][23:16];
437	        5'd3:  status_pkt_byte = status_words[0][15:8];
438	        5'd4:  status_pkt_byte = status_words[0][7:0];
439	        // Word 1 (bytes 5-8)
440	        5'd5:  status_pkt_byte = status_words[1][31:24];
441	        5'd6:  status_pkt_byte = status_words[1][23:16];
442	        5'd7:  status_pkt_byte = status_words[1][15:8];
443	        5'd8:  status_pkt_byte = status_words[1][7:0];
444	        // Word 2 (bytes 9-12)
445	        5'd9:  status_pkt_byte = status_words[2][31:24];
446	        5'd10: status_pkt_byte = status_words[2][23:16];
447	        5'd11: status_pkt_byte = status_words[2][15:8];
448	        5'd12: status_pkt_byte = status_words[2][7:0];
449	        // Word 3 (bytes 13-16)
450	        5'd13: status_pkt_byte = status_words[3][31:24];
451	        5'd14: status_pkt_byte = status_words[3][23:16];
452	        5'd15: status_pkt_byte = status_words[3][15:8];
453	        5'd16: status_pkt_byte = status_words[3][7:0];
454	        // Word 4 (bytes 17-20)
455	        5'd17: status_pkt_byte = status_words[4][31:24];
456	        5'd18: status_pkt_byte = status_words[4][23:16];
457	        5'd19: status_pkt_byte = status_words[4][15:8];
458	        5'd20: status_pkt_byte = status_words[4][7:0];
459	        // Word 5 (bytes 21-24)
460	        5'd21: status_pkt_byte = status_words[5][31:24];
461	        5'd22: status_pkt_byte = status_words[5][23:16];
462	        5'd23: status_pkt_byte = status_words[5][15:8];
463	        5'd24: status_pkt_byte = status_words[5][7:0];
464	        // Footer (byte 25)
465	        5'd25: status_pkt_byte = FOOTER;
466	        default: status_pkt_byte = 8'h00;
467	    endcase
468	end
469	
470	// ============================================================================
471	// MAIN FSM (ft_clk domain)
472	// ============================================================================
473	// Write FSM and Read FSM share the bus. Write FSM operates when Read FSM
474	// is idle. Read FSM takes priority when host has data available.
475	
476	always @(posedge ft_clk or negedge ft_effective_reset_n) begin
477	    if (!ft_effective_reset_n) begin
478	        wr_state       <= WR_IDLE;
479	        wr_byte_idx    <= 5'd0;
480	        rd_state       <= RD_IDLE;
481	        rd_byte_cnt    <= 2'd0;
482	        rd_cmd_complete <= 1'b0;
483	        rd_shift_reg   <= 32'd0;
484	        ft_data_out    <= 8'd0;
485	        ft_data_oe     <= 1'b0;
486	        ft_rd_n        <= 1'b1;
487	        ft_wr_n        <= 1'b1;
488	        ft_oe_n        <= 1'b1;
489	        ft_siwu        <= 1'b0;
490	        cmd_data       <= 32'd0;
491	        cmd_valid      <= 1'b0;
492	        cmd_opcode     <= 8'd0;
493	        cmd_addr       <= 8'd0;
494	        cmd_value      <= 16'd0;
495	        doppler_data_pending <= 1'b0;
496	        cfar_data_pending    <= 1'b0;
497	        sample_counter       <= 12'd0;
498	    end else begin
499	        // Default: clear one-shot signals
500	        cmd_valid <= 1'b0;
501	
502	        // Data-pending flag management
503	        if (doppler_valid_ft)
504	            doppler_data_pending <= 1'b1;
505	        if (cfar_valid_ft)
506	            cfar_data_pending <= 1'b1;
507	
508	        // ================================================================
509	        // READ FSM — Host → FPGA command path (4-byte sequential read)
510	        // ================================================================
511	        case (rd_state)
512	            RD_IDLE: begin
513	                // Only start reading if write FSM is idle and host has data
514	                if (wr_state == WR_IDLE && !ft_rxf_n) begin
515	                    ft_oe_n    <= 1'b0;      // Assert OE: FT2232H drives bus
516	                    ft_data_oe <= 1'b0;      // FPGA releases bus
517	                    rd_state   <= RD_OE_ASSERT;
518	                end
519	            end
520	
521	            RD_OE_ASSERT: begin
522	                // 1-cycle turnaround: OE asserted, bus settling
523	                if (!ft_rxf_n) begin
524	                    ft_rd_n  <= 1'b0;        // Assert RD: start reading
525	                    rd_state <= RD_READING;
526	                end else begin
527	                    // Host withdrew data — abort
528	                    ft_oe_n  <= 1'b1;
529	                    rd_state <= RD_IDLE;
530	                end
531	            end
532	
533	            RD_READING: begin
534	                // Sample byte and shift into command register
535	                // Byte order: opcode, addr, value_hi, value_lo
536	                rd_shift_reg <= {rd_shift_reg[23:0], ft_data};
537	                if (rd_byte_cnt == 2'd3) begin
538	                    // All 4 bytes received
539	                    ft_rd_n         <= 1'b1;
540	                    rd_byte_cnt     <= 2'd0;
541	                    rd_cmd_complete <= 1'b1;
542	                    rd_state        <= RD_DEASSERT;
543	                end else begin
544	                    rd_byte_cnt <= rd_byte_cnt + 2'd1;
545	                    // Keep reading if more data available
546	                    if (ft_rxf_n) begin
547	                        // Host ran out of data mid-command — abort
548	                        ft_rd_n         <= 1'b1;
549	                        rd_byte_cnt     <= 2'd0;
550	                        rd_cmd_complete <= 1'b0;
551	                        rd_state        <= RD_DEASSERT;
552	                    end
553	                end
554	            end
555	
556	            RD_DEASSERT: begin
557	                // Deassert OE (1 cycle after RD deasserted)
558	                ft_oe_n  <= 1'b1;
559	                // Only process if we received a full 4-byte command
560	                if (rd_cmd_complete) begin
561	                    rd_cmd_complete <= 1'b0;
562	                    rd_state <= RD_PROCESS;
563	                end else begin
564	                    // Incomplete command — discard
565	                    rd_state <= RD_IDLE;
566	                end
567	            end
568	
569	            RD_PROCESS: begin
570	                // Decode the assembled command word
571	                cmd_data   <= rd_shift_reg;
572	                cmd_opcode <= rd_shift_reg[31:24];
573	                cmd_addr   <= rd_shift_reg[23:16];
574	                cmd_value  <= rd_shift_reg[15:0];
575	                cmd_valid  <= 1'b1;
576	                rd_state   <= RD_IDLE;
577	            end
578	
579	            default: rd_state <= RD_IDLE;
580	        endcase
581	
582	        // ================================================================
583	        // WRITE FSM — FPGA → Host data streaming (byte-sequential)
584	        // ================================================================
585	        if (rd_state == RD_IDLE) begin
586	            case (wr_state)
587	                WR_IDLE: begin
588	                    ft_wr_n    <= 1'b1;
589	                    ft_data_oe <= 1'b0;   // Release data bus
590	
591	                    // Status readback takes priority
592	                    if (status_req_ft && ft_rxf_n) begin
593	                        wr_state    <= WR_STATUS_SEND;
594	                        wr_byte_idx <= 5'd0;
595	                    end
596	                    // Trigger on range_data_ready (1 cycle after range_valid_ft)
597	                    // so that range_profile_cap has settled from the CDC block.
598	                    // Gate on pending flags: only send when all enabled
599	                    // streams have fresh data (avoids stale doppler/CFAR)
600	                    else if (range_data_ready && stream_range_en
601	                             && (!stream_doppler_en || doppler_data_pending)
602	                             && (!stream_cfar_en    || cfar_data_pending)) begin
603	                        if (ft_rxf_n) begin  // No host read pending
604	                            wr_state    <= WR_DATA_SEND;
605	                            wr_byte_idx <= 5'd0;
606	                        end
607	                    end
608	                end
609	
610	                WR_DATA_SEND: begin
611	                    if (!ft_txe_n) begin
612	                        // TXE# low = TX FIFO has room
613	                        ft_data_oe  <= 1'b1;
614	                        ft_data_out <= data_pkt_byte;
615	                        ft_wr_n     <= 1'b0;   // Assert write strobe
616	
617	                        if (wr_byte_idx == DATA_PKT_LEN - 5'd1) begin
618	                            // Last byte of data packet
619	                            wr_state    <= WR_DONE;
620	                            wr_byte_idx <= 5'd0;
621	                        end else begin
622	                            wr_byte_idx <= wr_byte_idx + 5'd1;
623	                        end
624	                    end
625	                end
626	
627	                WR_STATUS_SEND: begin
628	                    if (!ft_txe_n) begin
629	                        ft_data_oe  <= 1'b1;
630	                        ft_data_out <= status_pkt_byte;
631	                        ft_wr_n     <= 1'b0;
632	
633	                        if (wr_byte_idx == STATUS_PKT_LEN - 5'd1) begin
634	                            wr_state    <= WR_DONE;
635	                            wr_byte_idx <= 5'd0;
636	                        end else begin
637	                            wr_byte_idx <= wr_byte_idx + 5'd1;
638	                        end
639	                    end
640	                end
641	
642	                WR_DONE: begin
643	                    ft_wr_n    <= 1'b1;
644	                    ft_data_oe <= 1'b0;   // Release data bus
645	                    // Clear pending flags — data consumed
646	                    doppler_data_pending <= 1'b0;
647	                    cfar_data_pending    <= 1'b0;
648	                    // Advance frame sync counter
649	                    if (sample_counter == NUM_CELLS - 12'd1)
650	                        sample_counter <= 12'd0;
651	                    else
652	                        sample_counter <= sample_counter + 12'd1;
653	                    wr_state   <= WR_IDLE;
654	                end
655	
656	                default: wr_state <= WR_IDLE;
657	            endcase
658	        end
659	    end
660	end
661	
662	endmodule
663

